// Flexible Example 1:
<Counter>
  <Counter.Label>Score: </Counter.Label>
  <Counter.Decrease icon="-" />
  <Counter.Count />
  <Counter.Increase icon="+" />
</Counter>

// Flexible Example 2: Different order!
<Counter>
  <Counter.Count />
  <Counter.Increase icon="" />
  <Counter.Decrease icon="" />
</Counter>

// Flexible Example 3: Omit components!
<Counter>
  <Counter.Increase icon="+" />
  <Counter.Decrease icon="-" />
  {/* No Count or Label! */}
</Counter>

// Compare to Prop Explosion (inflexible):
<Counter
  label="Score: "
  iconIncrease="+"
  iconDecrease="-"
  hideLabel={false}
  hideIncrease={false}
  hideDecrease={false}
  // Need even more props to change order!
/>
